import{_ as t,a as e,b as n,c}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as i,o as r,c as d,a2 as h}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Redundant Backup và Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Other/redundant-backup-and-read-source.md","filePath":"vi-VN/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),l={name:"vi-VN/Other/redundant-backup-and-read-source.md"};function p(u,a,s,o,b,k){return r(),d("div",null,[...a[0]||(a[0]=[h('<h1 id="redundant-backup-va-read-source-switching" tabindex="-1">Redundant Backup và Read Source Switching <a class="header-anchor" href="#redundant-backup-va-read-source-switching" aria-label="Permalink to &quot;Redundant Backup và Read Source Switching&quot;">​</a></h1><p>Redundant backup lưu một bản copy bổ sung của file đã upload.</p><p>Cả primary file và backup file đều có thể dùng làm read sources. Visitors thường không thấy khác biệt. Khác biệt duy nhất là storage channel nào serve file.</p><h2 id="redundant-backup-lam-đuoc-gi" tabindex="-1">Redundant Backup làm được gì <a class="header-anchor" href="#redundant-backup-lam-đuoc-gi" aria-label="Permalink to &quot;Redundant Backup làm được gì&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Store an extra copy</td><td>Back up files sang upload channel khác để giảm rủi ro khi một channel lỗi.</td></tr><tr><td>Switch read source</td><td>Sau khi backup thành công, switch file reads giữa primary channel và backup channel.</td></tr><tr><td>Single-file backup</td><td>Back up một file từ file details page.</td></tr><tr><td>Batch backup</td><td>Chọn nhiều files trong admin page và back up cùng lúc.</td></tr><tr><td>Global redundant backup</td><td>Back up files theo folder từ Other Settings.</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>Mở:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+t+'" alt="Redundant backup" loading="lazy"></p><p>Entry này phù hợp để thêm backups cho một folder hoặc tất cả files theo dạng bulk.</p><p>Backup channel có thể chọn thủ công, hoặc bạn chọn automatic switching để ImgBed tìm backup channel phù hợp.</p><h2 id="backup-tu-file-details" tabindex="-1">Backup từ File Details <a class="header-anchor" href="#backup-tu-file-details" aria-label="Permalink to &quot;Backup từ File Details&quot;">​</a></h2><p>Mở file details page trong admin panel và nhấn backup.</p><p><img src="'+e+'" alt="Backup in file details" loading="lazy"></p><p>Phù hợp nhất khi muốn back up một important file theo nhu cầu.</p><p>Sau khi backup thành công, file details page hiển thị available read sources.</p><h2 id="batch-backup-bang-selection" tabindex="-1">Batch Backup bằng Selection <a class="header-anchor" href="#batch-backup-bang-selection" aria-label="Permalink to &quot;Batch Backup bằng Selection&quot;">​</a></h2><p>Trong admin panel, chọn nhiều files và run batch backup.</p><p><img src="'+n+'" alt="Batch backup" loading="lazy"></p><p>Phù hợp để xử lý một nhóm files.</p><p>Selection backup, file details backup và redundant backup trong Other Settings đều dùng cùng backup system. Chúng chỉ là entry points khác nhau.</p><h2 id="switch-read-source-sau-backup" tabindex="-1">Switch Read Source sau Backup <a class="header-anchor" href="#switch-read-source-sau-backup" aria-label="Permalink to &quot;Switch Read Source sau Backup&quot;">​</a></h2><p>Sau khi backup hoàn tất, file details page cho phép switch read source:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>Đọc từ original upload channel.</td></tr><tr><td>Backup channel</td><td>Đọc từ backup channel.</td></tr></tbody></table><p><img src="'+c+'" alt="Switch read source after backup" loading="lazy"></p><p>Visitors không cần biết file đang được serve từ primary hay backup channel.</p><p>Read source bạn chọn sẽ trở thành preferred source cho file access sau này.</p><h2 id="khi-nao-backup-bi-skip" tabindex="-1">Khi nào Backup bị Skip <a class="header-anchor" href="#khi-nao-backup-bi-skip" aria-label="Permalink to &quot;Khi nào Backup bị Skip&quot;">​</a></h2><p>Các trường hợp sau sẽ bị skip trong quá trình backup. Chúng không phải lỗi.</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>File đã có backup sẽ không được back up lại.</td></tr><tr><td>Primary và backup channels giống nhau</td><td>Backup phải được lưu ở channel khác thì mới có ý nghĩa.</td></tr><tr><td>No usable backup channel</td><td>Không có alternative channel phù hợp.</td></tr></tbody></table><p>Tóm lại: backups phải đi sang channel khác, và files đã backed-up không tiêu tốn thêm dung lượng lần nữa.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>Channel được dùng khi file được upload lần đầu.</td></tr><tr><td>Backup channel</td><td>Channel lưu redundant copy.</td></tr><tr><td>Primary read source</td><td>File hiện được read từ primary channel.</td></tr><tr><td>Backup read source</td><td>File hiện được read từ backup channel.</td></tr></tbody></table><p>Primary và backup read sources có user-facing behavior giống nhau.</p><p>Miễn là backup file available, images, videos và download links vẫn hoạt động sau khi switch sang backup read source.</p><h2 id="đieu-gi-xay-ra-khi-file-bi-delete" tabindex="-1">Điều gì xảy ra khi File bị Delete <a class="header-anchor" href="#đieu-gi-xay-ra-khi-file-bi-delete" aria-label="Permalink to &quot;Điều gì xảy ra khi File bị Delete&quot;">​</a></h2><p>Khi file bị delete, ImgBed delete cả primary file và backup file.</p>',37)])])}const y=i(l,[["render",p]]);export{f as __pageData,y as default};
